    24→  critical: { label: 'Critical', color: 'text-red-400',    bg: 'bg-red-500/15 border border-red-600/40' },
    25→  // Legacy aliases from mock data
    26→  minor:    { label: 'Minor',    color: 'text-green-400',  bg: 'bg-green-500/15 border border-green-600/40' },
    27→  serious:  { label: 'Serious',  color: 'text-orange-400', bg: 'bg-orange-500/15 border border-orange-600/40' },
    28→};
    29→
    30→const statusConfig: Record<string, { label: string; color: string }> = {
    31→  open:              { label: 'Open',             color: 'text-red-400' },
    32→  investigating:     { label: 'Investigating',    color: 'text-yellow-400' },
    33→  action_required:   { label: 'Action Required',  color: 'text-orange-400' },
