    35→  resolved:          { label: 'Resolved',          color: 'text-emerald-400' },
    36→};
    37→
    38→const typeConfig: Record<string, { label: string; icon: typeof Shield }> = {
    39→  near_miss:            { label: 'Near Miss',           icon: AlertTriangle },
    40→  first_aid:            { label: 'First Aid',           icon: AlertCircle },
    41→  riddor:               { label: 'RIDDOR',              icon: AlertCircle },
    42→  dangerous_occurrence: { label: 'Dangerous Occurrence',icon: AlertTriangle },
    43→  environmental:        { label: 'Environmental',        icon: Shield },
    44→  // Legacy
    45→  'near-miss':          { label: 'Near Miss',           icon: AlertTriangle },
    46→  incident:             { label: 'Incident',            icon: AlertCircle },
    47→  hazard:               { label: 'Hazard',              icon: AlertTriangle },
    48→  'toolbox-talk':       { label: 'Toolbox Talk',        icon: FileText },
    49→  'mewp-check':         { label: 'MEWP Check',          icon: CheckCircle2 },
    50→};
    51→
    52→const defaultForm = {
    53→  title: '', type: 'near_miss', severity: 'medium', status: 'open',
    54→  project: '', location: '', date: new Date().toISOString().split('T')[0],
    55→  description: '', immediate_action: '', injured_party: '',
    56→  reported_by_name: '', riddor_reportable: false,
    57→};
    58→type FormData = typeof defaultForm;
    59→
    60→export function Safety() {
    61→  const { useList, useCreate, useUpdate, useDelete } = useSafety;
    62→  const { data: raw = [], isLoading, refetch } = useList();
    63→  const incidents = raw as AnyRow[];
    64→  const createM = useCreate(); const updateM = useUpdate(); const deleteM = useDelete();
    65→
    66→  const [categoryTab, setCategoryTab] = useState('all');
    67→  const [filter, setFilter] = useState('all');
    68→  const [search, setSearch] = useState('');
    69→  const [showModal, setShowModal] = useState(false);
    70→  const [editId, setEditId] = useState<string | null>(null);
    71→  const [form, setForm] = useState<FormData>(defaultForm);
    72→  const [selectedId, setSelectedId] = useState<string | null>(null);
    73→
    74→  const TYPE_MAP: Record<string, string[]> = {
    75→    all:          [],
    76→    incidents:    ['incident','first_aid','riddor'],
    77→    near_misses:  ['near-miss','near_miss'],
    78→    hazards:      ['hazard','dangerous_occurrence','environmental'],
    79→    mewp:         ['mewp-check','mewp_check'],
    80→    toolbox:      ['toolbox-talk','toolbox_talk'],
    81→    riddor:       ['riddor'],
    82→  };
    83→
    84→  const filtered = incidents
    85→    .filter(i => {
