    87→        const types = TYPE_MAP[categoryTab] ?? [];
    88→        return types.includes(String(i.type ?? ''));
    89→      }
    90→      return true;
    91→    })
    92→    .filter(i => filter === 'all' || i.status === filter || i.severity === filter)
    93→    .filter(i => !search || String(i.title).toLowerCase().includes(search.toLowerCase()) ||
    94→      String(i.project).toLowerCase().includes(search.toLowerCase()));
    95→
    96→  const counts = {
    97→    open: incidents.filter(i => i.status === 'open' || i.status === 'investigating' || i.status === 'action_required').length,
    98→    critical: incidents.filter(i => i.severity === 'critical' || i.severity === 'serious').length,
    99→    riddor: incidents.filter(i => i.riddor_reportable || i.type === 'riddor').length,
   100→    closed: incidents.filter(i => i.status === 'closed' || i.status === 'resolved').length,
   101→  };
   102→
   103→  const selected = incidents.find(i => String(i.id) === selectedId);
   104→
   105→  const openCreate = () => { setForm(defaultForm); setEditId(null); setShowModal(true); };
   106→  const openEdit = (i: AnyRow) => {
   107→    setForm({
   108→      title: String(i.title??''), type: String(i.type??'near_miss'), severity: String(i.severity??'medium'),
   109→      status: String(i.status??'open'), project: String(i.project??''), location: String(i.location??''),
   110→      date: String(i.date??new Date().toISOString().split('T')[0]), description: String(i.description??''),
   111→      immediate_action: String(i.immediate_action??''), injured_party: String(i.injured_party??''),
   112→      reported_by_name: String(i.reported_by_name??i.reportedBy??''), riddor_reportable: Boolean(i.riddor_reportable),
   113→    });
   114→    setEditId(String(i.id)); setShowModal(true);
   115→  };
   116→
   117→  const handleSubmit = async (e: React.FormEvent) => {
   118→    e.preventDefault();
   119→    if (editId) { await updateM.mutateAsync({ id: editId, data: form }); }
   120→    else { await createM.mutateAsync(form); }
   121→    setShowModal(false);
   122→  };
   123→
   124→  const handleDelete = async (id: string) => {
   125→    if (!confirm('Delete this incident record?')) return;
   126→    await deleteM.mutateAsync(id); setSelectedId(null);
   127→  };
   128→
   129→  const inp = "w-full bg-gray-800 border border-gray-700 rounded-xl px-4 py-2.5 text-white text-sm placeholder-gray-600 focus:outline-none focus:border-red-500 transition-colors";
   130→  const lbl = "block text-xs font-semibold text-gray-400 mb-1.5 uppercase tracking-wide";
   131→
   132→  return (
   133→    <div className="min-h-full space-y-6">
   134→      {/* Header */}
   135→      <div className="flex items-start justify-between gap-4 flex-wrap">
   136→        <div>
   137→          <h1 className="text-3xl font-bold text-white">Safety</h1>
   138→          <p className="text-sm text-gray-400 mt-1">{incidents.length} records · {counts.open} open · {counts.riddor} RIDDOR reportable</p>
   139→        </div>
   140→        <div className="flex gap-2">
   141→          <button onClick={() => refetch()} className="p-2 rounded-xl bg-gray-800 text-gray-400 hover:text-white"><RefreshCw className="w-4 h-4" /></button>
   142→          <button onClick={openCreate} className="flex items-center gap-2 rounded-xl bg-gradient-to-r from-red-600 to-rose-600 px-4 py-2 text-sm font-semibold text-white hover:from-red-500 transition-all shadow-lg shadow-red-500/20">
   143→            <Plus className="w-4 h-4" /> Report Incident
   144→          </button>
   145→        </div>
   146→      </div>
   147→
   148→      {/* KPI Cards */}
   149→      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
   150→        {[
   151→          { label: 'Open Incidents',  value: counts.open,     color: 'text-red-400',    bg: 'from-red-500/10 to-red-600/5',      border: 'border-red-800/40',     icon: AlertCircle },
   152→          { label: 'Critical / Serious', value: counts.critical, color: 'text-orange-400', bg: 'from-orange-500/10 to-orange-600/5', border: 'border-orange-800/40',  icon: AlertTriangle },
   153→          { label: 'RIDDOR Reportable', value: counts.riddor,  color: 'text-purple-400', bg: 'from-purple-500/10 to-purple-600/5', border: 'border-purple-800/40',  icon: FileText },
   154→          { label: 'Closed / Resolved', value: counts.closed, color: 'text-emerald-400',bg: 'from-emerald-500/10 to-emerald-600/5',border: 'border-emerald-800/40',icon: CheckCircle2 },
   155→        ].map(({ label, value, color, bg, border, icon: Icon }) => (
   156→          <div key={label} className={clsx('rounded-2xl border bg-gradient-to-br p-5', bg, border)}>
   157→            <div className="flex items-start justify-between">
   158→              <div><p className="text-xs text-gray-400 mb-1">{label}</p><p className={clsx('text-3xl font-black', color)}>{value}</p></div>
   159→              <div className="p-2 rounded-xl bg-gray-800/60"><Icon className={clsx('w-5 h-5', color)} /></div>
   160→            </div>
   161→          </div>
   162→        ))}
   163→      </div>
   164→
   165→      {/* Category sub-nav */}
   166→      <div className="flex gap-1 bg-gray-900 border border-gray-800 rounded-xl p-1 overflow-x-auto">
   167→        {[
   168→          {id:'all',        label:'All Records'},
   169→          {id:'incidents',  label:'Incidents'},
   170→          {id:'near_misses',label:'Near Misses'},
   171→          {id:'hazards',    label:'Hazards'},
   172→          {id:'mewp',       label:'MEWP Checks'},
   173→          {id:'toolbox',    label:'Toolbox Talks'},
   174→          {id:'riddor',     label:'RIDDOR'},
   175→        ].map(t => (
   176→          <button key={t.id} onClick={() => setCategoryTab(t.id)}
