   178→              categoryTab===t.id ? 'bg-red-600 text-white' : 'text-gray-400 hover:text-white hover:bg-gray-800')}>
   179→            {t.label}
   180→            <span className={clsx('ml-1.5 text-xs', categoryTab===t.id ? 'text-red-200' : 'text-gray-600')}>
   181→              {t.id==='all' ? incidents.length
   182→                : incidents.filter(i => (TYPE_MAP[t.id]??[]).includes(String(i.type??''))).length}
   183→            </span>
   184→          </button>
