   192→        <ResponsiveContainer width="100%" height={200}>
   193→          <LineChart data={SAFETY_TREND_DATA}>
   194→            <CartesianGrid strokeDasharray="3 3" stroke="#1f2937" vertical={false} />
   195→            <XAxis dataKey="month" stroke="#6b7280" tick={{ fontSize: 11 }} />
   196→            <YAxis stroke="#6b7280" tick={{ fontSize: 11 }} />
   197→            <Tooltip contentStyle={{ backgroundColor: '#111827', border: '1px solid #374151', borderRadius: 10, fontSize: 11 }} />
   198→            <Legend wrapperStyle={{ fontSize: 11 }} />
   199→            <Line type="monotone" dataKey="incidents"    name="Incidents"      stroke="#ef4444" strokeWidth={2} dot={{ r: 3 }} />
   200→            <Line type="monotone" dataKey="nearMisses"   name="Near Misses"    stroke="#f59e0b" strokeWidth={2} dot={{ r: 3 }} />
   201→            <Line type="monotone" dataKey="toolboxTalks" name="Toolbox Talks"  stroke="#22c55e" strokeWidth={2} dot={{ r: 3 }} />
   202→          </LineChart>
   203→        </ResponsiveContainer>
   204→      </div>
   205→
   206→      {/* Search + Filters */}
   207→      <div className="flex flex-wrap gap-3 items-center">
   208→        <div className="relative flex-1 max-w-sm">
   209→          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
   210→          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search incidents..."
   211→            className="w-full bg-gray-800 border border-gray-700 rounded-xl pl-9 pr-3 py-2 text-sm text-white placeholder-gray-500 focus:outline-none focus:border-red-500" />
   212→        </div>
   213→        {['all','open','investigating','closed'].map(s => (
   214→          <button key={s} onClick={() => setFilter(s)}
   215→            className={clsx('rounded-full px-3.5 py-1.5 text-xs font-semibold transition-all capitalize',
   216→              filter===s ? 'bg-red-600 text-white' : 'bg-gray-800 text-gray-300 hover:bg-gray-700')}>
   217→            {s==='all' ? 'All' : s}
   218→          </button>
   219→        ))}
   220→      </div>
   221→
   222→      {isLoading && <div className="flex justify-center py-16"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>}
   223→
   224→      {/* Incidents List */}
   225→      <div className="space-y-3">
   226→        {filtered.map(inc => {
   227→          const sev = severityConfig[String(inc.severity)] ?? severityConfig.low;
   228→          const stat = statusConfig[String(inc.status)] ?? statusConfig.open;
   229→          const typeInfo = typeConfig[String(inc.type)] ?? { label: String(inc.type), icon: Shield };
   230→          const TypeIcon = typeInfo.icon;
   231→          return (
   232→            <div key={String(inc.id)}
   233→              className={clsx(
   234→                'rounded-2xl border bg-gray-900 p-5 cursor-pointer transition-all hover:border-gray-700',
   235→                selectedId === String(inc.id) ? 'border-red-600/50 ring-1 ring-red-500/20' : 'border-gray-800'
   236→              )}
   237→              onClick={() => setSelectedId(prev => prev===String(inc.id)?null:String(inc.id))}>
   238→              <div className="flex items-start justify-between gap-3">
   239→                <div className="flex items-start gap-3 flex-1 min-w-0">
   240→                  <div className={clsx('p-2 rounded-xl shrink-0', sev.bg)}>
