   254→                      {(inc.reported_by_name || inc.reportedBy) ? <span>By: {String(inc.reported_by_name ?? inc.reportedBy)}</span> : null}
   255→                    </div>
   256→                    {selectedId === String(inc.id) && !!inc.description && (
   257→                      <p className="mt-2 text-xs text-gray-400 leading-relaxed">{String(inc.description)}</p>
   258→                    )}
   259→                  </div>
   260→                </div>
   261→                <div className="flex flex-col items-end gap-2 shrink-0">
   262→                  <span className={clsx('rounded-full px-2.5 py-1 text-xs font-bold', sev.bg, sev.color)}>{sev.label}</span>
   263→                  <span className={clsx('text-xs font-semibold', stat.color)}>{stat.label}</span>
   264→                </div>
   265→              </div>
   266→              {selectedId === String(inc.id) && (
   267→                <div className="flex gap-2 mt-4 pt-4 border-t border-gray-800" onClick={e => e.stopPropagation()}>
   268→                  <button onClick={() => openEdit(inc)}
   269→                    className="flex-1 flex items-center justify-center gap-1.5 rounded-xl bg-gray-800 hover:bg-gray-700 py-2 text-xs font-semibold text-white transition-colors">
   270→                    <Edit2 className="w-3.5 h-3.5" /> Edit Record
   271→                  </button>
   272→                  {String(inc.status) !== 'closed' && (
   273→                    <button onClick={() => updateM.mutateAsync({ id: String(inc.id), data: { status: 'closed' } })}
   274→                      className="flex-1 flex items-center justify-center gap-1.5 rounded-xl bg-green-600/20 hover:bg-green-600/30 border border-green-600/30 py-2 text-xs font-semibold text-green-400 transition-colors">
   275→                      <CheckCircle2 className="w-3.5 h-3.5" /> Close Incident
   276→                    </button>
   277→                  )}
   278→                  <button onClick={() => handleDelete(String(inc.id))}
   279→                    className="rounded-xl bg-gray-800 hover:bg-red-900/20 px-3 py-2 text-red-500 hover:text-red-400 transition-colors">
   280→                    <Trash2 className="w-3.5 h-3.5" />
   281→                  </button>
   282→                </div>
   283→              )}
   284→            </div>
   285→          );
   286→        })}
   287→        {!isLoading && filtered.length === 0 && (
   288→          <div className="text-center py-16 text-gray-500">
   289→            <Shield className="w-12 h-12 mx-auto mb-3 text-gray-700" />
   290→            <p className="font-medium">No incidents recorded</p>
   291→            <button onClick={openCreate} className="mt-3 text-sm text-red-400 hover:text-red-300">+ Report an incident</button>
   292→          </div>
   293→        )}
   294→      </div>
   295→
   296→      {/* Modal */}
   297→      {showModal && (
