    41→  const [form, setForm] = useState<FormData>(defaultForm);
    42→  const [selectedId, setSelectedId] = useState<string | null>(null);
    43→
    44→  const filtered = invoices
    45→    .filter(inv => filter === 'all' || inv.status === filter)
    46→    .filter(inv =>
    47→      !search || String(inv.number).toLowerCase().includes(search.toLowerCase()) ||
    48→      String(inv.client).toLowerCase().includes(search.toLowerCase())
