    50→
    51→  const totals = {
    52→    draft:   invoices.filter(i => i.status === 'draft').reduce((s, i) => s + Number(i.amount), 0),
    53→    sent:    invoices.filter(i => i.status === 'sent').reduce((s, i) => s + Number(i.amount), 0),
    54→    paid:    invoices.filter(i => i.status === 'paid').reduce((s, i) => s + Number(i.amount), 0),
    55→    overdue: invoices.filter(i => i.status === 'overdue').reduce((s, i) => s + Number(i.amount), 0),
    56→  };
    57→
    58→  // By project breakdown
    59→  const projectMap = new Map<string, { raised:number; paid:number; overdue:number; count:number }>();
    60→  invoices.forEach(i => {
    61→    const proj = String(i.project||i.client||'Unassigned');
    62→    const e = projectMap.get(proj) ?? { raised:0, paid:0, overdue:0, count:0 };
    63→    e.raised += Number(i.amount??0);
    64→    if (i.status==='paid') e.paid += Number(i.amount??0);
    65→    if (i.status==='overdue') e.overdue += Number(i.amount??0);
    66→    e.count++;
    67→    projectMap.set(proj, e);
    68→  });
    69→  const byProject = Array.from(projectMap.entries()).map(([name,v])=>({name,...v})).sort((a,b)=>b.raised-a.raised);
    70→
    71→  // Aged debt
