    73→    ...i,
    74→    daysAge: i.due_date ? Math.max(0, Math.round((Date.now()-new Date(String(i.due_date)).getTime())/86400000)) : 0,
    75→  } as AnyRow & { daysAge: number })).sort((a,b)=>b.daysAge-a.daysAge);
    76→
    77→  const selectedInv = invoices.find(i => i.id === selectedId);
