    91→      cis_deduction: String(inv.cis_deduction ?? inv.cisDeduction ?? '0'),
    92→      status: String(inv.status ?? 'draft'),
    93→      issue_date: String(inv.issue_date ?? inv.issueDate ?? ''),
    94→      due_date: String(inv.due_date ?? inv.dueDate ?? ''),
    95→      payment_terms: String(inv.payment_terms ?? 'Net 30'),
    96→      bank_account: String(inv.bank_account ?? ''),
    97→      notes: String(inv.notes ?? ''),
    98→    });
    99→    setEditId(String(inv.id));
   100→    setShowModal(true);
