   138→        </div>
   139→        <div className="flex gap-2">
   140→          <button onClick={() => refetch()} className="p-2 rounded-xl bg-gray-800 text-gray-400 hover:text-white">
   141→            <RefreshCw className="w-4 h-4" />
   142→          </button>
   143→          <button onClick={openCreate}
   144→            className="flex items-center gap-2 rounded-xl bg-gradient-to-r from-emerald-600 to-emerald-700 px-4 py-2 text-sm font-semibold text-white hover:from-emerald-500 transition-all">
   145→            <Plus className="w-4 h-4" /> New Invoice
   146→          </button>
   147→        </div>
   148→      </div>
   149→
   150→      {/* Sub-tab nav */}
   151→      <div className="flex gap-1 border-b border-gray-700 mb-6">
   152→        {([
   153→          { key:'invoices'  as const, label:'Invoices' },
   154→          { key:'byproject' as const, label:'By Project' },
   155→          { key:'aged'      as const, label:'Aged Debt', badge:agedDebt.filter(i=>i.status==='overdue').length },
   156→        ]).map(t=>(
   157→          <button key={t.key} onClick={()=>setSubTab(t.key)}
   158→            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab===t.key?'border-emerald-500 text-emerald-400':'border-transparent text-gray-400 hover:text-gray-200'}`}>
   159→            {t.label}
   160→            {'badge' in t && t.badge!=null && t.badge > 0 && <span className="text-xs px-1.5 py-0.5 rounded-full bg-red-900/60 text-red-400">{t.badge}</span>}
   161→          </button>
