   268→      {isLoading && <div className="flex justify-center py-20"><Loader2 className="w-8 h-8 animate-spin text-emerald-500" /></div>}
   269→
   270→      {/* Invoice Table */}
   271→      <div className="rounded-2xl border border-gray-800 bg-gray-900 overflow-hidden mb-8">
   272→        <div className="overflow-x-auto">
   273→          <table className="w-full text-sm">
   274→            <thead>
   275→              <tr className="border-b border-gray-800">
