     1→// Module: Projects — CortexBuild Ultimate  (Full Workspace with Subpages)
     2→import { useState } from 'react';
     3→import {
     4→  Plus, X, Trash2, Edit2, Search, ChevronRight, MapPin, Users, Calendar,
     5→  PoundSterling, TrendingUp, AlertTriangle, CheckCircle2, Clock, Building2,
     6→  BarChart3, FileText, Shield, ClipboardList, HardHat, ArrowLeft,
     7→  Loader2, RefreshCw, MessageSquare,
     8→} from 'lucide-react';
     9→import {
    10→  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend,
    11→  ResponsiveContainer, LineChart, Line,
    12→} from 'recharts';
    13→import {
    14→  useProjects, useInvoices, useTeam, useDocuments,
    15→  useRFIs, useChangeOrders, useSafety, useDailyReports,
    16→} from '../../hooks/useData';
    17→import type { ProjectStatus } from '../../types';
    18→import clsx from 'clsx';
    19→import { toast } from 'sonner';
    20→
    21→type AnyRow = Record<string, unknown>;
    22→
    23→// ─── Config ────────────────────────────────────────────────────────────────
    24→const STATUS_CFG: Record<string, { label:string; color:string; bg:string; dot:string }> = {
    25→  active:    { label:'Active',    color:'text-green-400',   bg:'bg-green-500/15 border border-green-600/50',    dot:'bg-green-400'  },
    26→  planning:  { label:'Planning',  color:'text-blue-400',    bg:'bg-blue-500/15 border border-blue-600/50',      dot:'bg-blue-400'   },
    27→  on_hold:   { label:'On Hold',   color:'text-yellow-400',  bg:'bg-yellow-500/15 border border-yellow-600/50',  dot:'bg-yellow-400' },
    28→  completed: { label:'Completed', color:'text-emerald-400', bg:'bg-emerald-500/15 border border-emerald-600/50',dot:'bg-emerald-400'},
    29→  archived:  { label:'Archived',  color:'text-gray-500',    bg:'bg-gray-700/50 border border-gray-600',         dot:'bg-gray-500'   },
    30→};
    31→const PROJECT_TYPES  = ['Commercial','Residential','Civil','Industrial','Healthcare','Fit-Out','Infrastructure','Refurbishment'];
    32→const PROJECT_PHASES = ['Pre-construction','Tender','Design','Foundation','Structural','Envelope','Internal Fit-Out','MEP','Finishing','Snagging','Handover'];
    33→const defaultForm    = { name:'', client:'', location:'', type:'Commercial', manager:'', budget:'', contract_value:'', workers:'0', start_date:'', end_date:'', status:'planning', phase:'Pre-construction', description:'' };
    34→type FormData = typeof defaultForm;
    35→
    36→function fmtM(n:number){ if(n>=1_000_000) return `£${(n/1_000_000).toFixed(1)}M`; if(n>=1_000) return `£${(n/1_000).toFixed(0)}K`; return `£${n.toLocaleString()}`; }
    37→function daysDiff(d:string){ const diff=(new Date(d).getTime()-Date.now())/86400000; return Math.round(diff); }
    38→
    39→// ═══════════════════════════════════════════════════════════════════════════
    40→// PROJECT WORKSPACE — full page when a project is selected
    41→// ═══════════════════════════════════════════════════════════════════════════
    42→type WorkspaceTab = 'overview'|'financials'|'team'|'documents'|'rfis'|'safety'|'reports';
    43→
    44→interface WorkspaceProps {
    45→  project: AnyRow;
    46→  onBack: () => void;
    47→  onEdit: () => void;
    48→}
    49→function ProjectWorkspace({ project, onBack, onEdit }: WorkspaceProps) {
    50→  const [tab, setTab] = useState<WorkspaceTab>('overview');
    51→  const pName = String(project.name ?? '');
    52→
    53→  // All hooks called unconditionally (React rules)
    54→  const { data: rawInv=[]  } = useInvoices.useList();
    55→  const { data: rawTeam=[]  } = useTeam.useList();
    56→  const { data: rawDocs=[]  } = useDocuments.useList();
    57→  const { data: rawRFIs=[]  } = useRFIs.useList();
    58→  const { data: rawCOs=[]   } = useChangeOrders.useList();
    59→  const { data: rawSafe=[]  } = useSafety.useList();
    60→  const { data: rawReps=[]  } = useDailyReports.useList();
    61→
    62→  // Filter by project
    63→  const invoices = (rawInv  as AnyRow[]).filter(i => String(i.project??'').toLowerCase().includes(pName.toLowerCase().split(' ')[0]));
    64→  const teamAll  = (rawTeam as AnyRow[]);
    65→  const docs     = (rawDocs as AnyRow[]).filter(d => String(d.project??'').toLowerCase().includes(pName.toLowerCase().split(' ')[0]));
    66→  const rfis     = (rawRFIs as AnyRow[]).filter(r => String(r.project??'').toLowerCase().includes(pName.toLowerCase().split(' ')[0]));
    67→  const cos      = (rawCOs  as AnyRow[]).filter(c => String(c.project??'').toLowerCase().includes(pName.toLowerCase().split(' ')[0]));
    68→  const safety   = (rawSafe as AnyRow[]).filter(s => String(s.project??'').toLowerCase().includes(pName.toLowerCase().split(' ')[0]));
    69→  const reports  = (rawReps as AnyRow[]).filter(r => String(r.project??'').toLowerCase().includes(pName.toLowerCase().split(' ')[0]));
    70→
    71→  const budget    = Number(project.budget??0);
    72→  const spent     = Number(project.spent??0);
    73→  const pct       = budget>0 ? (spent/budget)*100 : 0;
    74→  const progress  = Number(project.progress??0);
    75→  const endDate   = String(project.endDate??project.end_date??'');
    76→  const daysLeft  = endDate ? daysDiff(endDate) : null;
    77→  const statusCfg = STATUS_CFG[String(project.status??'')] ?? STATUS_CFG.planning;
    78→
    79→  const totalInvoiced = invoices.reduce((s,i)=>s+Number(i.amount??0),0);
    80→  const totalPaid     = invoices.filter(i=>i.status==='paid').reduce((s,i)=>s+Number(i.amount??0),0);
    81→  const openRFIs      = rfis.filter(r=>r.status==='open'||r.status==='pending').length;
    82→  const openSafety    = safety.filter(s=>s.status==='open'||s.status==='investigating').length;
    83→  const pendingCOs    = cos.filter(c=>c.status==='pending'||c.status==='draft').length;
    84→  const approvedCOVal = cos.filter(c=>c.status==='approved').reduce((s,c)=>s+Number(c.value??c.amount??0),0);
    85→
    86→  const TABS = [
    87→    { id:'overview',   label:'Overview',       icon:BarChart3       },
    88→    { id:'financials', label:'Financials',     icon:PoundSterling   },
    89→    { id:'team',       label:'Team',           icon:Users           },
    90→    { id:'documents',  label:'Documents',      icon:FileText        },
    91→    { id:'rfis',       label:'RFIs & COs',     icon:MessageSquare   },
    92→    { id:'safety',     label:'Safety',         icon:Shield          },
    93→    { id:'reports',    label:'Daily Reports',  icon:ClipboardList   },
    94→  ] as const;
    95→
    96→  return (
    97→    <div className="space-y-0">
    98→      {/* Breadcrumb */}
    99→      <div className="flex items-center gap-2 mb-4 text-sm">
   100→        <button onClick={onBack} className="flex items-center gap-1 text-gray-400 hover:text-white transition-colors">
   101→          <ArrowLeft className="w-4 h-4"/> Projects
   102→        </button>
   103→        <ChevronRight className="w-4 h-4 text-gray-600"/>
   104→        <span className="text-white font-medium">{pName}</span>
   105→      </div>
   106→
   107→      {/* Hero */}
   108→      <div className="bg-gradient-to-r from-gray-900 to-gray-900/60 border border-gray-800 rounded-2xl p-6 mb-4">
   109→        <div className="flex items-start justify-between mb-4">
   110→          <div className="flex-1 min-w-0">
   111→            <div className="flex items-center gap-3 mb-1 flex-wrap">
   112→              <h1 className="text-2xl font-bold text-white">{pName}</h1>
   113→              <span className={`text-xs px-2.5 py-1 rounded-full font-semibold border ${statusCfg.bg} ${statusCfg.color}`}>
   114→                {statusCfg.label}
   115→              </span>
   116→            </div>
   117→            <p className="text-gray-400 text-sm">{String(project.client??'')} &nbsp;·&nbsp; <MapPin className="inline w-3.5 h-3.5"/> {String(project.location??project.address??'')}</p>
   118→          </div>
   119→          <div className="flex items-center gap-2 ml-4 flex-shrink-0">
   120→            <button onClick={onEdit} className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-white text-sm rounded-lg transition-colors">
   121→              <Edit2 className="w-3.5 h-3.5"/> Edit
   122→            </button>
   123→          </div>
   124→        </div>
   125→
   126→        {/* Progress */}
   127→        <div className="mb-4">
   128→          <div className="flex items-center justify-between text-sm mb-1.5">
   129→            <span className="text-gray-400">Overall Progress</span>
   130→            <span className="font-bold text-blue-400">{progress}%</span>
   131→          </div>
   132→          <div className="h-3 bg-gray-800 rounded-full overflow-hidden">
   133→            <div className="h-full rounded-full bg-gradient-to-r from-blue-500 to-blue-400 transition-all" style={{width:`${progress}%`}}/>
   134→          </div>
   135→        </div>
   136→
   137→        {/* KPI row */}
   138→        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
   139→          <div className="bg-gray-800/60 rounded-xl p-3">
   140→            <p className="text-gray-400 text-xs mb-1">Contract Value</p>
   141→            <p className="text-white font-bold text-lg">{fmtM(Number(project.contractValue??project.contract_value??0))}</p>
   142→          </div>
   143→          <div className="bg-gray-800/60 rounded-xl p-3">
   144→            <p className="text-gray-400 text-xs mb-1">Budget Used</p>
   145→            <p className={`font-bold text-lg ${pct>90?'text-red-400':pct>70?'text-yellow-400':'text-green-400'}`}>{pct.toFixed(0)}%</p>
   146→            <p className="text-gray-500 text-xs">{fmtM(spent)} / {fmtM(budget)}</p>
   147→          </div>
   148→          <div className="bg-gray-800/60 rounded-xl p-3">
   149→            <p className="text-gray-400 text-xs mb-1">Days Remaining</p>
   150→            <p className={`font-bold text-lg ${daysLeft!==null&&daysLeft<30?'text-red-400':daysLeft!==null&&daysLeft<90?'text-yellow-400':'text-green-400'}`}>
   151→              {daysLeft !== null ? (daysLeft > 0 ? `${daysLeft}d` : 'Overdue') : '—'}
   152→            </p>
   153→            {!!endDate && <p className="text-gray-500 text-xs">Due {endDate}</p>}
   154→          </div>
   155→          <div className="bg-gray-800/60 rounded-xl p-3">
   156→            <p className="text-gray-400 text-xs mb-1">Workers On Site</p>
   157→            <p className="text-white font-bold text-lg">{String(project.workers??0)}</p>
   158→            <p className="text-gray-500 text-xs">{String(project.phase??project.current_phase??'—')}</p>
   159→          </div>
   160→        </div>
   161→      </div>
   162→
   163→      {/* Tab bar */}
   164→      <div className="flex gap-1 mb-4 bg-gray-900 border border-gray-800 rounded-xl p-1 overflow-x-auto">
   165→        {TABS.map(t => {
   166→          const Icon = t.icon;
   167→          return (
   168→            <button key={t.id} onClick={()=>setTab(t.id)}
   169→              className={clsx('flex items-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-all',
   170→                tab===t.id ? 'bg-blue-600 text-white shadow' : 'text-gray-400 hover:text-white hover:bg-gray-800')}>
   171→              <Icon className="w-3.5 h-3.5"/>{t.label}
   172→            </button>
   173→          );
   174→        })}
   175→      </div>
   176→
   177→      {/* Tab content */}
   178→      {tab==='overview' && (
   179→        <div className="space-y-4">
   180→          {/* Alert row */}
   181→          {(openSafety>0 || openRFIs>0 || pct>85) && (
   182→            <div className="flex gap-3 flex-wrap">
   183→              {openSafety>0 && <div className="flex items-center gap-2 bg-red-900/30 border border-red-700/50 rounded-xl px-4 py-2 text-sm text-red-300"><Shield className="w-4 h-4"/>{openSafety} open safety issue{openSafety>1?'s':''}</div>}
   184→              {openRFIs>0   && <div className="flex items-center gap-2 bg-orange-900/30 border border-orange-700/50 rounded-xl px-4 py-2 text-sm text-orange-300"><MessageSquare className="w-4 h-4"/>{openRFIs} open RFI{openRFIs>1?'s':''}</div>}
   185→              {pct>85       && <div className="flex items-center gap-2 bg-yellow-900/30 border border-yellow-700/50 rounded-xl px-4 py-2 text-sm text-yellow-300"><AlertTriangle className="w-4 h-4"/>{pct.toFixed(0)}% of budget used</div>}
   186→              {pendingCOs>0 && <div className="flex items-center gap-2 bg-blue-900/30 border border-blue-700/50 rounded-xl px-4 py-2 text-sm text-blue-300"><ClipboardList className="w-4 h-4"/>{pendingCOs} pending change order{pendingCOs>1?'s':''}</div>}
   187→            </div>
   188→          )}
