   179→                    <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3}/><stop offset="95%" stopColor="#ef4444" stopOpacity={0}/>
   180→                  </linearGradient>
   181→                  <linearGradient id="profitGrad2" x1="0" y1="0" x2="0" y2="1">
   182→                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/><stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
   183→                  </linearGradient>
   184→                </defs>
   185→                <CartesianGrid strokeDasharray="3 3" stroke="#374151"/>
   186→                <XAxis dataKey="month" stroke="#9ca3af"/>
   187→                <YAxis stroke="#9ca3af"/>
   188→                <Tooltip contentStyle={{backgroundColor:'#111827',border:'1px solid #374151'}}/>
   189→                <Area type="monotone" dataKey="revenue" stroke="#3b82f6" fill="url(#revGrad)"/>
