   191→                <Area type="monotone" dataKey="profit"  stroke="#10b981" fill="url(#profitGrad2)"/>
   192→              </AreaChart>
   193→            </ResponsiveContainer>
   194→          </div>
   195→
   196→          <div className="grid grid-cols-2 gap-4">
   197→            <div className="rounded-2xl border border-gray-800 bg-gray-900 p-5">
   198→              <h3 className="mb-4 text-sm font-semibold text-white">Revenue by Project Type</h3>
   199→              <ResponsiveContainer width="100%" height={250}>
   200→                <PieChart>
   201→                  <Pie data={REVENUE_BY_TYPE} cx="50%" cy="50%" labelLine={false}
   202→                    label={({name,percent})=>`${name} ${((percent??0)*100).toFixed(0)}%`}
   203→                    outerRadius={80} dataKey="value">
   204→                    {REVENUE_BY_TYPE.map((entry,idx)=><Cell key={idx} fill={entry.color}/>)}
   205→                  </Pie>
   206→                  <Tooltip formatter={(v:number)=>`£${(v/1000).toFixed(0)}K`}/>
   207→                </PieChart>
   208→              </ResponsiveContainer>
   209→            </div>
   210→            <div className="rounded-2xl border border-gray-800 bg-gray-900 p-5">
   211→              <h3 className="mb-4 text-sm font-semibold text-white">Invoice Aging</h3>
   212→              <div className="space-y-3">
   213→                {INVOICE_AGING.map((item,idx)=>(
   214→                  <div key={idx}>
   215→                    <div className="mb-1 flex justify-between text-xs">
   216→                      <span className="text-gray-400">{item.range}</span>
   217→                      <span className="font-semibold text-white">£{(item.amount/1000).toFixed(0)}K</span>
   218→                    </div>
   219→                    <div className="h-2 w-full rounded-full bg-gray-700">
   220→                      <div className="h-full rounded-full bg-gradient-to-r from-amber-500 to-orange-500" style={{width:`${item.percentage}%`}}/>
   221→                    </div>
   222→                  </div>
   223→                ))}
   224→              </div>
   225→            </div>
   226→          </div>
   227→        </div>
   228→      )}
   229→
   230→      {/* Safety */}
   231→      {activeTab==='safety' && (
   232→        <div className="space-y-6">
   233→          <div className="grid grid-cols-4 gap-4">
   234→            {[
   235→              {label:'Safety Score',       value:`${safetyScore}/100`,   color:'text-emerald-400'},
   236→              {label:'RIDDOR Incidents',   value:String(riddorCount),    color:'text-green-400' },
   237→              {label:'Open Incidents',     value:String(openIncidents),  color:'text-orange-400'},
   238→              {label:'Toolbox Talks',      value:String(toolboxCount),   color:'text-blue-400'  },
   239→            ].map((kpi,idx)=>(
   240→              <div key={idx} className="rounded-xl border border-gray-800 bg-gray-900 p-4">
   241→                <p className="text-xs text-gray-400">{kpi.label}</p>
   242→                <p className={clsx('mt-2 text-2xl font-bold', kpi.color)}>{kpi.value}</p>
   243→              </div>
   244→            ))}
   245→          </div>
   246→
   247→          <div className="rounded-2xl border border-gray-800 bg-gray-900 p-5">
   248→            <h3 className="mb-4 text-sm font-semibold text-white">Safety Trends — 7 Months</h3>
   249→            <ResponsiveContainer width="100%" height={300}>
   250→              <LineChart data={SAFETY_TREND}>
   251→                <CartesianGrid strokeDasharray="3 3" stroke="#374151"/>
   252→                <XAxis dataKey="month" stroke="#9ca3af"/>
   253→                <YAxis stroke="#9ca3af"/>
   254→                <Tooltip contentStyle={{backgroundColor:'#111827',border:'1px solid #374151'}}/>
   255→                <Legend/>
   256→                <Line type="monotone" dataKey="incidents"    name="Incidents"     stroke="#ef4444" strokeWidth={2}/>
   257→                <Line type="monotone" dataKey="nearMisses"   name="Near Misses"   stroke="#fbbf24" strokeWidth={2}/>
   258→                <Line type="monotone" dataKey="toolboxTalks" name="Toolbox Talks" stroke="#3b82f6" strokeWidth={2}/>
   259→              </LineChart>
   260→            </ResponsiveContainer>
   261→          </div>
   262→
   263→          <div className="rounded-2xl border border-gray-800 bg-gray-900 p-5">
   264→            <h3 className="mb-4 text-sm font-semibold text-white">Incident Types Distribution</h3>
