      style={{ animationDelay: `${delay}ms`, padding: '0', cursor: onClick ? 'pointer' : 'default', textAlign: 'left', width: '100%', border: 'none', overflow: 'hidden' }}
    >
      {/* Amber top accent line */}
      <div style={{
        position: 'absolute', top: 0, left: '0', right: '0', height: '3px',
