          <StatCard
            label="Revenue Collected" value={fmtM(totalRevenue)} sub="+12.4% this month"
            positive={true} icon={TrendingUp as any} delay={100} onClick={() => setModule('invoicing')}
          />
        </div>
        <div className="animate-fade-up delay-2">
          <StatCard
            label="Active Projects" value={String(activeProjects.length)} sub="In progress"
            positive={true} icon={FolderOpen as any} delay={180} onClick={() => setModule('projects')}
          />
        </div>
        <div className="animate-fade-up delay-3">
          <StatCard
            label="Workers On Site" value={String(workerCount)} sub="Across all sites"
            positive={true} icon={HardHat as any} delay={260} onClick={() => setModule('teams')}
          />
        </div>
        <div className="animate-fade-up delay-4">
          <StatCard
            label="Outstanding" value={fmtM(outstanding)} sub="Awaiting payment"
            positive={false} icon={FileText as any} delay={340} onClick={() => setModule('invoicing')}
          />
        </div>
        <div className="animate-fade-up delay-5">
          <StatCard
            label="Open Incidents" value={String(openIncidents)} sub={openIncidents === 0 ? 'All resolved' : 'Needs action'}
            positive={openIncidents === 0} icon={ShieldCheck as any} delay={420} onClick={() => setModule('safety')}
          />
        </div>
        <div className="animate-fade-up delay-6">
          <StatCard
            label="Open RFIs" value={String(openRFIs)} sub="Awaiting response"
            positive={false} icon={MessageSquare as any} delay={500} onClick={() => setModule('rfis')}
          />
        </div>
      </div>

      {/* ── Charts + Project Status ─────────────────────── */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '24px' }}>
        {/* Revenue Chart */}
        <div className="card card-grid animate-fade-up delay-3" style={{ padding: '24px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
            <div>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '14px', fontWeight: 700, color: 'var(--slate-100)', letterSpacing: '-0.01em' }}>Revenue vs Profit</h3>
              <p style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-500)', letterSpacing: '0.08em', textTransform: 'uppercase', marginTop: '2px' }}>Last 6 months · GBP</p>
            </div>
            {/* Legend */}
            <div style={{ display: 'flex', gap: '12px' }}>
              {[['#3b82f6', 'Revenue'], ['#10b981', 'Profit']].map(([color, label]) => (
                <div key={label} style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                  <div style={{ width: '8px', height: '8px', borderRadius: '2px', background: color }} />
                  <span style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-400)', letterSpacing: '0.06em' }}>{label}</span>
                </div>
              ))}
            </div>
          </div>
          <ResponsiveContainer width="100%" height={220}>
            <AreaChart data={chartData}>
              <defs>
                <linearGradient id="revGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.25}/>
                  <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                </linearGradient>
                <linearGradient id="profitGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#10b981" stopOpacity={0.25}/>
                  <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(59,83,120,0.15)" vertical={false} />
              <XAxis dataKey="month" stroke="var(--slate-500)" tick={{ fontFamily: 'JetBrains Mono', fontSize: 10 }} axisLine={false} tickLine={false} />
              <YAxis stroke="var(--slate-500)" tick={{ fontFamily: 'JetBrains Mono', fontSize: 10 }} axisLine={false} tickLine={false} tickFormatter={v => `£${(v/1000).toFixed(0)}K`} />
              <Tooltip
                contentStyle={{
                  background: 'var(--slate-900)', border: '1px solid var(--slate-700)',
                  borderRadius: '8px', fontFamily: 'JetBrains Mono', fontSize: '11px',
                  color: 'var(--slate-200)',
                }}
              />
              <Area type="monotone" dataKey="revenue" stroke="#3b82f6" strokeWidth={2} fill="url(#revGrad)" dot={false} />
              <Area type="monotone" dataKey="profit"  stroke="#10b981" strokeWidth={2} fill="url(#profitGrad)" dot={false} />
            </AreaChart>
          </ResponsiveContainer>
        </div>

        {/* Project Status */}
        <div className="card card-grid animate-fade-up delay-4" style={{ padding: '24px' }}>
          <div style={{ marginBottom: '20px' }}>
            <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '14px', fontWeight: 700, color: 'var(--slate-100)', letterSpacing: '-0.01em' }}>Project Progress</h3>
            <p style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-500)', letterSpacing: '0.08em', textTransform: 'uppercase', marginTop: '2px' }}>Active sites · % complete</p>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            {activeProjects.map(proj => (
              <div key={String(proj.id)}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '6px' }}>
                  <span style={{ fontFamily: 'var(--font-body)', fontSize: '12px', fontWeight: 600, color: 'var(--slate-200)' }}>
                    {String(proj.name ?? '').split(' ').slice(0, 2).join(' ')}
                  </span>
                  <span style={{ fontFamily: 'var(--font-mono)', fontSize: '11px', fontWeight: 700, color: 'var(--amber-400)' }}>
                    {String(proj.progress ?? 0)}%
                  </span>
                </div>
                <div className="progress-bar" style={{ background: 'var(--slate-800)' }}>
                  <div className="progress-bar-fill" style={{ width: `${Number(proj.progress ?? 0)}%` }} />
                </div>
                <div style={{ display: 'flex', gap: '12px', marginTop: '6px' }}>
                  <span style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-500)' }}>
                    £{(Number(proj.budget ?? 0) / 1_000_000).toFixed(1)}M budget
                  </span>
                  <span style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-500)' }}>
                    £{(Number(proj.spent ?? 0) / 1_000_000).toFixed(1)}M spent
                  </span>
                </div>
              </div>
            ))}
            {activeProjects.length === 0 && (
              <div style={{ textAlign: 'center', padding: '32px 0' }}>
                <p style={{ fontFamily: 'var(--font-mono)', fontSize: '11px', color: 'var(--slate-500)' }}>No active projects</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* ── Active Projects + Activity Feed ─────────────── */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 340px', gap: '16px', marginBottom: '24px' }}>
        {/* Project list */}
        <div className="animate-fade-up delay-4">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
            <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '13px', fontWeight: 700, color: 'var(--slate-100)', letterSpacing: '-0.01em' }}>Active Projects</h3>
            <button
              onClick={() => setModule('projects')}
              style={{
                display: 'flex', alignItems: 'center', gap: '4px',
                background: 'none', border: 'none', cursor: 'pointer',
                fontFamily: 'var(--font-mono)', fontSize: '10px', color: 'var(--amber-400)',
                letterSpacing: '0.06em', transition: 'gap 0.2s',
              }}
            >
              VIEW ALL <ArrowRight style={{ width: '12px', height: '12px' }} />
            </button>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
            {activeProjects.map(proj => (
              <div
                key={String(proj.id)}
                className="card card-hover"
                style={{ padding: '18px 20px', cursor: 'pointer', border: '1px solid var(--slate-800)' }}
                onClick={() => setModule('projects')}
              >
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px' }}>
                  <div>
                    <p style={{ fontFamily: 'var(--font-display)', fontSize: '13px', fontWeight: 700, color: 'var(--slate-100)' }}>{String(proj.name ?? '')}</p>
                    <p style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', color: 'var(--slate-500)', marginTop: '2px' }}>{String(proj.client ?? '')}</p>
                  </div>
                  <span className="badge badge-amber">{String(proj.progress ?? 0)}%</span>
                </div>
                <div className="progress-bar" style={{ marginBottom: '12px' }}>
                  <div className="progress-bar-fill" style={{ width: `${Number(proj.progress ?? 0)}%` }} />
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '8px' }}>
                  {[
                    ['Budget', `£${((Number(proj.budget ?? 0)) / 1_000_000).toFixed(1)}M`],
                    ['Spent', `£${((Number(proj.spent ?? 0)) / 1_000_000).toFixed(1)}M`],
                    ['Workers', String(proj.workers ?? 0)],
                  ].map(([label, val]) => (
                    <div key={label}>
                      <div className="text-label-xs" style={{ marginBottom: '2px' }}>{label}</div>
                      <div style={{ fontFamily: 'var(--font-mono)', fontSize: '12px', fontWeight: 600, color: 'var(--slate-200)' }}>{val}</div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Activity feed */}
        <div className="card card-grid animate-fade-up delay-5" style={{ padding: '24px' }}>
          <div style={{ marginBottom: '20px' }}>
            <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '14px', fontWeight: 700, color: 'var(--slate-100)', letterSpacing: '-0.01em' }}>Recent Activity</h3>
            <p style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-500)', letterSpacing: '0.08em', textTransform: 'uppercase', marginTop: '2px' }}>Live feed · all modules</p>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '0' }}>
            {recentActivities.map((act, idx) => (
              <div
                key={idx}
                style={{
                  display: 'flex', alignItems: 'flex-start', gap: '12px',
                  padding: '10px 0',
                  borderBottom: idx < recentActivities.length - 1 ? '1px solid var(--slate-800)' : 'none',
                  cursor: 'pointer',
                }}
                onClick={() => setModule(act.module)}
              >
                <div style={{
                  width: '8px', height: '8px', borderRadius: '50%', marginTop: '5px', flexShrink: 0,
                  background: act.dotColor, boxShadow: `0 0 6px ${act.dotColor}`,
                }} />
                <div style={{ flex: 1, minWidth: 0 }}>
                  <p style={{ fontFamily: 'var(--font-body)', fontSize: '12px', color: 'var(--slate-300)', lineHeight: 1.4, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {act.label}
                  </p>
                  {act.time && (
                    <p style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-500)', marginTop: '2px', letterSpacing: '0.04em' }}>
                      {act.time}
                    </p>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── Quick Actions ───────────────────────────────── */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '12px', marginBottom: '24px' }}>
        {([
          { label: 'New Invoice',   icon: FileText,       module: 'invoicing'     as Module, color: 'var(--amber-400)' },
          { label: 'Log Incident',  icon: AlertCircle,    module: 'safety'        as Module, color: 'var(--red-400)'    },
          { label: 'New RFI',       icon: MessageSquare,   module: 'rfis'          as Module, color: 'var(--slate-300)' },
          { label: 'Daily Report',  icon: Activity,      module: 'daily-reports' as Module, color: 'var(--emerald-400)' },
        ] as { label: string; icon: React.FC<{ style?: React.CSSProperties }>; module: Module; color: string }[]).map((action, idx) => {
          const Icon = action.icon;
          return (
            <button
              key={idx}
              onClick={() => setModule(action.module)}
              className={`card card-hover animate-fade-up delay-${idx + 4}`}
              style={{
                padding: '16px',
                display: 'flex', alignItems: 'center', gap: '12px',
                cursor: 'pointer', border: '1px solid var(--slate-800)',
                background: 'var(--slate-900)',
                transition: 'all 0.2s var(--ease-out)',
                position: 'relative', overflow: 'hidden',
              }}
            >
              {/* Hover fill */}
              <div style={{
                position: 'absolute', inset: 0, pointerEvents: 'none',
                background: `linear-gradient(135deg, ${action.color}08 0%, transparent 60%)`,
              }} />
              <div style={{
                width: '36px', height: '36px', borderRadius: '8px',
                background: `${action.color}15`,
                border: `1px solid ${action.color}25`,
                display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
              }}>
                <Icon style={{ width: '16px', height: '16px', color: action.color }} />
              </div>
              <span style={{
                fontFamily: 'var(--font-body)', fontSize: '12px', fontWeight: 600,
                color: 'var(--slate-200)', textAlign: 'left',
              }}>
                {action.label}
              </span>
            </button>
          );
        })}
      </div>

      {/* ── Safety Banner ───────────────────────────────── */}
      <div
        className="card animate-fade-up delay-6"
        style={{
          padding: '20px 24px',
          background: openIncidents === 0
            ? 'linear-gradient(135deg, rgba(16,185,129,0.06) 0%, var(--slate-900) 100%)'
            : 'linear-gradient(135deg, rgba(245,158,11,0.06) 0%, var(--slate-900) 100%)',
          border: `1px solid ${openIncidents === 0 ? 'rgba(16,185,129,0.2)' : 'rgba(245,158,11,0.2)'}`,
          display: 'flex', alignItems: 'center', gap: '16px',
        }}
      >
        {openIncidents === 0
          ? <CheckCircle2 style={{ width: '22px', height: '22px', color: 'var(--emerald-400)', flexShrink: 0 }} />
          : <AlertCircle style={{ width: '22px', height: '22px', color: 'var(--amber-400)', flexShrink: 0 }} />
        }
        <div>
          <p style={{ fontFamily: 'var(--font-display)', fontSize: '13px', fontWeight: 700, color: 'var(--slate-100)' }}>
            {openIncidents === 0
              ? safetyDays > 0 ? `${safetyDays} safety record${safetyDays > 1 ? 's' : ''} on file` : 'No open safety incidents'
              : `${openIncidents} open safety incident${openIncidents > 1 ? 's' : ''} require attention`
            }
          </p>
          <p style={{ fontFamily: 'var(--font-mono)', fontSize: '10px', color: openIncidents === 0 ? 'var(--emerald-400)' : 'var(--amber-400)', marginTop: '2px', letterSpacing: '0.04em' }}>
            {openIncidents === 0 ? 'Excellent safety record — keep up the great work' : 'Review and close out incidents promptly'}
          </p>
        </div>
        {openIncidents > 0 && (
          <button
            onClick={() => setModule('safety')}
            style={{
              marginLeft: 'auto', flexShrink: 0,
              display: 'flex', alignItems: 'center', gap: '4px',
              background: 'rgba(245,158,11,0.1)', border: '1px solid rgba(245,158,11,0.2)',
              borderRadius: '6px', padding: '6px 12px', cursor: 'pointer',
              fontFamily: 'var(--font-mono)', fontSize: '10px', fontWeight: 600,
              color: 'var(--amber-400)', letterSpacing: '0.06em', transition: 'background 0.2s',
            }}
          >
            REVIEW <ArrowRight style={{ width: '12px', height: '12px' }} />
          </button>
        )}
      </div>
    </div>
  );
}

