  if (openRFIs > 0) alerts.push({ id: 'rfi', title: `${openRFIs} RFI${openRFIs > 1 ? 's' : ''} awaiting response`, severity: 'warning', module: 'rfis', time: 'Pending' });

  // Activity feed
